	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript securely executes a user-provided Lua script to calculate the final price
// of a product based on the given context. Implements critical security mitigations:
// 1. Strict sandboxing of Lua environment (removes dangerous globals/modules)
// 2. Determinism enforcement (removes non-deterministic math functions)
// 3. Instruction limit to prevent DoS via infinite loops
// 4. Protected execution for all Lua operations
// 5. Strict validation of function signature and return type
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create isolated Lua state with strict resource limits
	L := lua.NewState(
		lua.Options{
			SkipOpenLibs:   true,  // Prevent automatic loading of unsafe standard libraries
			RegistrySize:   1024,
			CallStackSize:  256,   // Corrected field name from StackSize to CallStackSize
		},
	)
	defer L.Close()

	// SANDBOXING: Remove all dangerous globals and modules
	dangerousGlobals := []string{
		"os", "io", "debug", "package", "require", "load", "loadfile", "dofile",
		"collectgarbage", "coroutine", "module", "rawequal", "rawget", "rawset",
		"newproxy", "ffi", "jit", // Additional security hardening
	}
	for _, name := range dangerousGlobals {
		L.SetGlobal(name, lua.LNil)
	}

	// SANDBOXING: Sanitize math module to ensure deterministic execution
	mathTable := L.GetGlobal("math")
	if tbl, ok := mathTable.(*lua.LTable); ok {
		L.SetField(tbl, "random", lua.LNil)
		L.SetField(tbl, "randomseed", lua.LNil)
		// Explicitly preserve safe math functions if needed by merchants
		// (basic arithmetic operators remain available without math module)
	}

	// SECURITY: Enforce instruction limit to prevent CPU exhaustion attacks
	const maxInstructions = 10000
	instructionCount := 0
	// Set hook on Lua state to count instructions and enforce limit
	L.SetHook(func(l *lua.LState, ar *lua.Debug) {
		instructionCount++
		if instructionCount > maxInstructions {
			l.RaiseError("execution terminated: instruction limit exceeded")
		}
	}, lua.HookCount, 1)

	// SAFETY: Load script in protected mode (prevents panic on syntax errors)
	// Fixed: Capture both return values from LoadString
	chunk, err := L.LoadString(script)
	if err != nil {
		return 0, fmt.Errorf("invalid Lua script syntax: %w", err)
	}

	// SAFETY: Execute script chunk in protected mode with instruction counting
	// Use loaded chunk directly instead of stack value
	if err := L.CallByParam(lua.P{
		Fn:      chunk,
		NRet:    0,
		Protect: true,
	}); err != nil {
		return 0, fmt.Errorf("script execution failed: %w", err)
	}
	// Removed L.Pop(1) since chunk was not pushed to stack

	// VALIDATION: Verify required function exists and is callable
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("script must define global function 'calculate_final_price'")
	}

	// BUILD CONTEXT: Convert Go context to sandboxed Lua table
	ctxTable := L.NewTable()
	for k, v := range ctx {
		// Keys are validated as strings, values strictly converted to numbers
		L.SetField(ctxTable, k, lua.LNumber(v))
	}

	// EXECUTION: Call pricing function in protected mode with instruction counting
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("pricing function execution failed: %w", err)
	}

	// VALIDATION: Strictly verify return type is numeric
	result := L.Get(-1)
	L.Pop(1)
	if result.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price must return a number (got %s)", result.Type().String())
	}

	return float64(result.(lua.LNumber)), nil
