import (
	"fmt"

	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript securely executes a user-provided Lua script to calculate the final price
// of a product based on the given context. Implements critical security mitigations:
// 1. Sandboxed environment (no access to os/io/debug/package/etc.)
// 2. Strict instruction limit to prevent DoS attacks
// 3. Panic recovery for safe error handling
// 4. Type validation of all inputs/outputs
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create isolated Lua state with NO standard libraries loaded
	L := lua.NewState(lua.Options{SkipOpenLibs: true})
	defer L.Close()

	// Enforce strict sandbox: empty global environment
	L.Env = L.NewTable()

	var finalPrice float64
	var execError error

	// Execute Lua operations in isolated closure for panic recovery
	func() {
		defer func() {
			if r := recover(); r != nil {
				// Normalize panic types to consistent error message
				var errMsg string
				switch v := r.(type) {
				case *lua.ApiError:
					errMsg = v.Error()
				case string:
					errMsg = v
				case error:
					errMsg = v.Error()
				default:
					errMsg = fmt.Sprintf("%v", r)
				}
				execError = fmt.Errorf("Lua execution failed: %s", errMsg)
			}
		}()

		// Enforce strict instruction limit to prevent DoS attacks
		const maxInstructions = 100000
		instructionCount := 0
		L.SetHook(func(l *lua.LState) {
			instructionCount++
			if instructionCount > maxInstructions {
				panic("instruction limit exceeded: possible infinite loop or DoS attempt")
			}
		}, lua.HookCount, 1)
		defer L.SetHook(nil, 0, 0) // Clean up hook after execution

		// Load script explicitly to control environment
		lf, err := L.LoadString(script)
		if err != nil {
			execError = fmt.Errorf("script compilation failed: %w", err)
			return
		}

		// CRITICAL FIX: Explicitly bind script chunk to sandboxed environment
		// Ensures global assignments (like function definitions) land in L.Env
		L.SetEnv(lf, L.Env)

		// Execute script chunk in sandboxed environment
		if err := L.Call(0, 0); err != nil {
			execError = fmt.Errorf("script execution failed: %w", err)
			return
		}

		// Verify required function exists and is callable in sandbox environment
		fn := L.GetGlobal("calculate_final_price")
		if fn.Type() != lua.LTFunction {
			execError = fmt.Errorf("calculate_final_price must be a global function")
			return
		}

		// Safely convert context to Lua table (all values validated as numbers)
		ctxTable := L.NewTable()
		for k, v := range ctx {
			// Explicitly convert to LNumber to prevent type confusion
			L.SetField(ctxTable, k, lua.LNumber(v))
		}

		// Execute pricing function with protected call
		if err := L.CallByParam(lua.P{
			Fn:      fn,
			NRet:    1,
			Protect: true, // Catches Lua runtime errors
		}, ctxTable); err != nil {
			execError = fmt.Errorf("function execution failed: %w", err)
			return
		}

		// Validate and extract result
		result := L.Get(-1)
		L.Pop(1)

		if result.Type() != lua.LTNumber {
			execError = fmt.Errorf("function must return a number (got %s)", result.Type().String())
			return
		}

		finalPrice = float64(result.(lua.LNumber))
	}()

	if execError != nil {
		return 0, execError
	}

	return finalPrice, nil
}

