// ExecutePricingScript executes a user-provided Lua script to calculate the final price.
// The script must define a global function named `calculate_final_price` that accepts a context table
// and returns a numeric value. The context map is converted to a Lua table with string keys and numeric values.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	L := lua.NewState()
	defer L.Close()

	// Execute the provided Lua script to define the pricing function
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Verify that calculate_final_price is defined as a function
	calcFunc := L.GetGlobal("calculate_final_price")
	if calcFunc.Type() != lua.LTFunction {
		return 0, fmt.Errorf("global 'calculate_final_price' is not a function (got %s)", calcFunc.Type().String())
	}

	// Convert Go context map to Lua table
	contextTable := L.CreateTable(len(ctx), 0)
	for key, value := range ctx {
		L.SetField(contextTable, key, lua.LNumber(value))
	}

	// Prepare stack: [function, context_table]
	L.Push(calcFunc)
	L.Push(contextTable)

	// Call the Lua function: 1 argument, expect 1 return value (using protected call)
	if err := L.PCall(1, 1, nil); err != nil {
		return 0, fmt.Errorf("error calling calculate_final_price: %w", err)
	}

	// Validate and extract return value
	resultVal := L.Get(-1)
	if resultVal.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price must return a number (got %s)", resultVal.Type().String())
	}

	return float64(resultVal.(lua.LNumber)), nil
}

